// frontend/src/pages/ProfilePage.js
import { useState, useEffect } from 'react';
import { useAuth } from '../context/AuthContext';
import API from '../api/axios';

const ProfilePage = () => {
  const { user, setUser } = useAuth();

  const [name, setName] = useState(user?.name || '');
  const [bio, setBio] = useState(user?.bio || '');
  const [pic, setPic] = useState(null);
  const [curPw, setCurPw] = useState('');
  const [newPw, setNewPw] = useState('');
  const [msg, setMsg] = useState('');
  const [darkMode, setDarkMode] = useState(false);

  useEffect(() => {
    const saved = localStorage.getItem("user-theme");
    setDarkMode(saved === "dark");
  }, []);

  const handleProfile = async (e) => {
    e.preventDefault();
    setMsg('');

    const fd = new FormData();
    fd.append('name', name);
    fd.append('bio', bio);
    if (pic) fd.append('profilePic', pic);

    try {
      const { data } = await API.put('/auth/profile', fd);
      setUser(data);
      setMsg('Profile updated successfully!');
    } catch (err) {
      setMsg(err.response?.data?.message || 'Error updating profile');
    }
  };

  const handlePassword = async (e) => {
    e.preventDefault();
    setMsg('');

    try {
      await API.put('/auth/change-password', {
        currentPassword: curPw,
        newPassword: newPw,
      });

      setMsg('Password changed successfully!');
      setCurPw('');
      setNewPw('');
    } catch (err) {
      setMsg(err.response?.data?.message || 'Error changing password');
    }
  };

  const picSrc = user?.profilePic
    ? `http://localhost:5000/uploads/${user.profilePic}`
    : '/default-avatar.png';

  /* ================= THEME ================= */
  const styles = {
  page: {
    background: darkMode
      ? "#0f2e25" // dark green background
      : "#FAE8ED", // light pink
    minHeight: '100vh',
    padding: '40px 20px',
    display: 'flex',
    justifyContent: 'center',
    alignItems: 'center',
    color: darkMode ? "#d1fae5" : "#0c4b34",
  },

  container: {
    width: '100%',
    maxWidth: '650px',
    backgroundColor: darkMode
      ? "#163d2f" // deep green card
      : "#f7c6d9", // soft pink card
    padding: '35px',
    borderRadius: '25px',
    boxShadow: darkMode
      ? "0 0 25px rgba(0,0,0,0.6)"
      : "0 12px 35px rgba(0,0,0,0.12)",
    textAlign: 'center',
  },

  heading: {
    fontSize: '34px',
    marginBottom: '20px',
    fontWeight: 'bold',
    color: darkMode ? "#a7f3d0" : "#0c4b34",
  },

  profilePic: {
    width: '130px',
    height: '130px',
    borderRadius: '50%',
    objectFit: 'cover',
    marginBottom: '20px',
    border: darkMode ? '4px solid #1f5c45' : '5px solid #fff',
    boxShadow: '0 6px 18px rgba(0,0,0,0.15)',
  },

  message: {
    marginBottom: '15px',
    fontWeight: 'bold',
    color: '#ff4d4d',
  },

  form: {
    display: 'flex',
    flexDirection: 'column',
    gap: '14px',
    marginTop: '20px',
    marginBottom: '30px',
    textAlign: 'left',
  },

  subHeading: {
    fontSize: '20px',
    fontWeight: 'bold',
    textAlign: 'center',
    marginBottom: '5px',
    color: darkMode ? "#bbf7d0" : "#0c4b34",
  },

  input: {
    padding: '14px 18px',
    borderRadius: '50px',
    border: darkMode ? "1px solid #1f5c45" : "1px solid transparent",
    outline: 'none',
    backgroundColor: darkMode ? "#0f2e25" : "#fff",
    color: darkMode ? "#ecfdf5" : "#000",
    fontSize: '15px',
  },

  textarea: {
    padding: '14px 18px',
    borderRadius: '15px',
    border: darkMode ? "1px solid #1f5c45" : "1px solid transparent",
    outline: 'none',
    backgroundColor: darkMode ? "#0f2e25" : "#fff",
    color: darkMode ? "#ecfdf5" : "#000",
    fontSize: '15px',
    resize: 'none',
  },

  fileWrapper: {
    display: "flex",
    alignItems: "center",
    justifyContent: "space-between",
    gap: "10px",
    padding: "10px",
    borderRadius: "12px",
    background: darkMode ? "#0f2e25" : "#fff",
    border: darkMode ? "1px solid #1f5c45" : "1px solid #ddd",
  },

  fileInput: {
    display: "none",
  },

  fileLabel: {
    padding: "10px 16px",
    borderRadius: "20px",
    background: darkMode
      ? "#a7f3d0" // light green button in dark mode
      : "rgb(12,75,52)", // dark green button in light mode
    color: darkMode ? "#022c22" : "#fff",
    cursor: "pointer",
    fontWeight: "bold",
    fontSize: "14px",
  },

  fileName: {
    fontSize: "13px",
    opacity: 0.8,
    color: darkMode ? "#a7f3d0" : "#333",
  },

  button: {
    padding: '14px',
    borderRadius: '50px',
    border: 'none',
    fontWeight: 'bold',
    cursor: 'pointer',
    backgroundColor: darkMode
      ? "#34d399" // green button
      : "rgb(12, 75, 52)", // dark green
    color: darkMode ? "#022c22" : "#fff",
    transition: '0.3s ease',
  },
};

  return (
    <div style={styles.page}>
      <div style={styles.container}>
        <h2 style={styles.heading}>My Profile</h2>

        <img src={picSrc} alt="Profile" style={styles.profilePic} />

        {msg && <p style={styles.message}>{msg}</p>}

        {/* EDIT PROFILE */}
        <form style={styles.form} onSubmit={handleProfile}>
          <h3 style={styles.subHeading}>Edit Profile</h3>

          <input
            value={name}
            onChange={(e) => setName(e.target.value)}
            placeholder="Display name"
            style={styles.input}
          />

          <textarea
            value={bio}
            onChange={(e) => setBio(e.target.value)}
            placeholder="Short bio..."
            rows={3}
            style={styles.textarea}
          />

          {/* FIXED FILE INPUT */}
          <div style={styles.fileWrapper}>
            <label htmlFor="fileUpload" style={styles.fileLabel}>
              📁 Choose File
            </label>

            <span style={styles.fileName}>
              {pic ? pic.name : "No file chosen"}
            </span>

            <input
              id="fileUpload"
              type="file"
              accept="image/*"
              onChange={(e) => setPic(e.target.files[0])}
              style={styles.fileInput}
            />
          </div>

          <button type="submit" style={styles.button}>
            Save Profile
          </button>
        </form>

        {/* PASSWORD */}
        <form style={styles.form} onSubmit={handlePassword}>
          <h3 style={styles.subHeading}>Change Password</h3>

          <input
            type="password"
            placeholder="Current password"
            value={curPw}
            onChange={(e) => setCurPw(e.target.value)}
            style={styles.input}
          />

          <input
            type="password"
            placeholder="New password"
            value={newPw}
            onChange={(e) => setNewPw(e.target.value)}
            style={styles.input}
          />

          <button type="submit" style={styles.button}>
            Change Password
          </button>
        </form>
      </div>
    </div>
  );
};

export default ProfilePage;
